CREATE VIEW `ads_video_cn_login_detail_view` (`id` COMMENT "自增ID", `log_id` COMMENT "uni-id-log._id", `log_type` COMMENT "操作类型 uni-id-log.type", `login_type` COMMENT "登录类型 uni-id-log.login_type", `user_id` COMMENT "uni-id-log.user_id", `ip` COMMENT "uni-id-log.ip", `os` COMMENT "uni-id-log.os", `platform` COMMENT "uni-id-log.platform", `state` COMMENT "结果:0 失败,1 成功 uni-id-log.state", `create_time` COMMENT "uni-id-log._add_time")
COMMENT "用户域用户登录信息表" AS SELECT `ods`.`ods_tidb_cdvideo_tidb_xcx_login`.`Id`, `ods`.`ods_tidb_cdvideo_tidb_xcx_login`.`log_id`, `ods`.`ods_tidb_cdvideo_tidb_xcx_login`.`log_type`, `ods`.`ods_tidb_cdvideo_tidb_xcx_login`.`login_type`, `ods`.`ods_tidb_cdvideo_tidb_xcx_login`.`user_id`, `ods`.`ods_tidb_cdvideo_tidb_xcx_login`.`ip`, `ods`.`ods_tidb_cdvideo_tidb_xcx_login`.`os`, `ods`.`ods_tidb_cdvideo_tidb_xcx_login`.`platform`, `ods`.`ods_tidb_cdvideo_tidb_xcx_login`.`state`, `ods`.`ods_tidb_cdvideo_tidb_xcx_login`.`create_time`
FROM `ods`.`ods_tidb_cdvideo_tidb_xcx_login`;